class Solution(object):
    def maximumSum(self, nums):
        # Group by remainder mod 3
        groups = [[], [], []]
        for v in nums:
            groups[v % 3].append(v)
        for g in groups:
            g.sort(reverse=True)

        def top(g, cnt):
            return sum(g[:cnt]) if len(g) >= cnt else None

        ans = 0
        # Case 1: 0+0+0
        v = top(groups[0], 3)
        if v is not None: ans = max(ans, v)
        # Case 2: 1+1+1
        v = top(groups[1], 3)
        if v is not None: ans = max(ans, v)
        # Case 3: 2+2+2
        v = top(groups[2], 3)
        if v is not None: ans = max(ans, v)
        # Case 4: 0+1+2
        if groups[0] and groups[1] and groups[2]:
            ans = max(ans, groups[0][0] + groups[1][0] + groups[2][0])
        return ans
